#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=5e5+5;
int f[MAXN][2],n,ans=llinf;
vector<int> g[MAXN];
void dfs(int u,int fa)
{
	f[u][1]=1;
	f[u][0]=0;
	FOI(s,g[u])
	{
		if(s==fa)continue;
		dfs(s,u);
		f[u][1]+=min(f[s][0],f[s][1]);
		f[u][0]+=f[s][1];
	}
	ans=min(ans,min(f[u][1],f[u][0]));
}
signed main(void)
{

    //freopen(".in","r",stdin);
