	ios::sync_with_stdio(0);
	cin.tie(0);
	cin>>n;
	FOR(i,1,n)
	{
		int x,k;
		cin>>x>>k;
		FOR(j,1,k)
		{
			int s;
			cin>>s;
			g[x].pb(s);
			g[s].pb(x);
		}
	}
	dfs(1,1);
	cout<<min(f[1][1],f[1][0]);
    return false;
}
